salesforce-composite:execute-composite-r.salesforce-composite:request-body:
#[%dw 2.0
import capitalize, remove from dw::core::Strings
output application/json
var apiVersion = "v66.0"
var contactUuid = vars.contactUuid
var supplierId = vars.id default ""
var createContactPayload = payload filterObject ($ != null) mapObject ((v, k) -> do {
	var newK = capitalize(k) remove " " ++ "__c"
	---
	{
		(newK): v
	}
}
   
)
---
{
	allOrNone: true,
	compositeRequest: [{
		referenceId: "supplierLookup",
		method: "GET",
		url: "/services/data/$(apiVersion)/query?q=SELECT+Id+FROM+Supplier__c+WHERE+UUID__c='$(supplierId)'+LIMIT+1"
	},
		{
		referenceId: "createContact",
		method: "POST",
		url: "/services/data/$(apiVersion)/sobjects/ContactInformation__c",
		body: createContactPayload ++ {
			"UUID__c": contactUuid,
			"Supplier__c": "@{supplierLookup.records[0].Id}"
		}
	}]
}]

salesforce:upsert.salesforce:records:
#[%dw 2.0
import capitalize, remove from dw::core::Strings
var updateContactPayload = (payload filterObject ($$ != null) mapObject((v, k) -> {
    (capitalize(k) remove " " ++ "__c"): v
})) ++  { UUID__c: vars.id }
---
[updateContactPayload]]

ee:message.ee:set-payload:
%dw 2.0
import camelize, remove from dw::core::Strings
output application/json
var paging = {
	limit: attributes.queryParams.limit default 25,
	offset: attributes.queryParams.limit default 0
}
fun transform(o: Object): Object =
    o filterObject((v, k) -> lower(k) != "id" and lower(k) != "type") mapObject((v, k) -> k match {
	case "Type" -> {
	}
	
	case "CreatedDate" -> {
		createdAt: v
	}
	
	case "LastModifiedDate" -> {
		modifiedAt: v
	}
	case "UUID__c" -> {
		id: v
	}

	else -> {
		(camelize(k remove "__c")): v
	}
})
var results = payload map (transform($))
---
{
	paging: paging,
	results: results
}
